diff --git a/src/pages/[section]/[slug].astro b/src/pages/[section]/[slug].astro
new file mode 100644
index 0000000..2fb9028
--- /dev/null
+++ b/src/pages/[section]/[slug].astro
@@ -0,0 +1,22 @@
+---
+import ArticleLayout from "../../layouts/ArticleLayout.astro";
+import { getAllArticles, getArticle } from "../../lib/articles";
+
+export function getStaticPaths() {
+  return getAllArticles().map((article) => ({
+    params: {
+      section: article.section,
+      slug: article.slug
+    }
+  }));
+}
+
+const { section, slug } = Astro.params;
+const article = getArticle(section ?? "", slug ?? "");
+
+if (!article) {
+  throw new Error(`Article not found: ${section}/${slug}`);
+}
+---
+
+<ArticleLayout article={article} />
